parameters.jsCode:
// Supondo que a string original esteja em input
const input = $input.item.json.output || "";

function cleanText(text) {
  // Remove aspas duplas
  let cleaned = text.replace(/"/g, "");

  // Remove pares de asteriscos duplos
  cleaned = cleaned.replace(/\*\*/g, "");

  // Remove parênteses que podem quebrar JSON
  cleaned = cleaned.replace(/[()]/g, "");

  // Remove outros caracteres problemáticos para JSON
  cleaned = cleaned.replace(/[\[\]{}]/g, "");

  // Remove caracteres de escape problemáticos
  cleaned = cleaned.replace(/\\/g, "");

  // Remove caracteres de controle, exceto quebras de linha
  cleaned = cleaned.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, "");

  // Remove espaços extras antes e depois da string
  cleaned = cleaned.trim();

  // Mantém \n exatamente como está, não altera

  return cleaned;
}

const output = cleanText(input);

// Retorna no formato esperado pelo n8n
return [
  {
    json: {
      output: output
    }
  }
];

